-- Create ALBUM_MASTER Table
CREATE TABLE public."ALBUM_MASTER" (
    "ALBUM_ID" bigint PRIMARY KEY,
    "TITLE" text NOT NULL,
    "ARTIST" text NOT NULL,
    "RELEASE_YEAR" integer,
    "IMAGE_URL" text,
    "VINYL_IMAGE_URL" text,
    "CUSTOM_COLOR_HEX" text,
    "CUSTOM_STYLE_TYPE" text,
    "TRACKS" jsonb
);

-- Create USER_VINYL Table
CREATE TABLE public."USER_VINYL" (
    "USER_VINYL_ID" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "USER_ID" uuid NOT NULL,
    "ALBUM_ID" bigint NOT NULL REFERENCES public."ALBUM_MASTER"("ALBUM_ID"),
    "STATUS" text NOT NULL,
    "PURCHASE_DATE" timestamp with time zone,
    "PURCHASE_PRICE" integer,
    "ADDED_AT" timestamp with time zone DEFAULT now()
);

-- Create VINYL_TAG Table
CREATE TABLE public."VINYL_TAG" (
    "TAG_ID" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "ALBUM_ID" bigint NOT NULL REFERENCES public."ALBUM_MASTER"("ALBUM_ID"),
    "TAG_TYPE" text,
    "TAG_NAME" text NOT NULL,
    CONSTRAINT "vinyl_tag_album_name_key" UNIQUE ("ALBUM_ID", "TAG_NAME")
);

-- Enable Supabase Realtime for the USER_VINYL table
-- This allows our apps to receive instant updates when a vinyl is added or modified
ALTER PUBLICATION supabase_realtime ADD TABLE public."USER_VINYL";

-- Add MARKET_PRICE column to ALBUM_MASTER Table
-- Run this manually in the Supabase SQL Editor: the column was missing, which
-- caused createAlbumMaster() to strip MARKET_PRICE from every save (PGRST204).
ALTER TABLE public."ALBUM_MASTER" ADD COLUMN IF NOT EXISTS "MARKET_PRICE" integer;

-- ============================================================
-- Row Level Security (RLS)
-- Run this manually in the Supabase SQL Editor.
--
-- Access model:
--   * Anyone (including logged-out visitors) can READ everything —
--     public dashboards (/user/[id]) must render collections for
--     non-members.
--   * Only authenticated users can WRITE, and USER_VINYL/PROFILES
--     rows can only be written by their owner (auth.uid()).
--   * ALBUM_MASTER/VINYL_TAG are shared master data: any signed-in
--     user may insert/update (scan & search flows create these),
--     but anonymous clients may not.
-- ============================================================

-- ALBUM_MASTER: public read / authenticated insert / no update or delete
ALTER TABLE public."ALBUM_MASTER" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "album_master_read_all"    ON public."ALBUM_MASTER";
DROP POLICY IF EXISTS "album_master_insert_auth" ON public."ALBUM_MASTER";
DROP POLICY IF EXISTS "album_master_update_auth" ON public."ALBUM_MASTER";
CREATE POLICY "album_master_read_all"    ON public."ALBUM_MASTER" FOR SELECT USING (true);
CREATE POLICY "album_master_insert_auth" ON public."ALBUM_MASTER" FOR INSERT TO authenticated WITH CHECK (true);
-- Update is deliberately disabled to prevent malicious overwrites of shared data

-- VINYL_TAG: public read / authenticated insert / no delete
ALTER TABLE public."VINYL_TAG" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "vinyl_tag_read_all"    ON public."VINYL_TAG";
DROP POLICY IF EXISTS "vinyl_tag_insert_auth" ON public."VINYL_TAG";
DROP POLICY IF EXISTS "vinyl_tag_delete_auth" ON public."VINYL_TAG";
CREATE POLICY "vinyl_tag_read_all"    ON public."VINYL_TAG" FOR SELECT USING (true);
CREATE POLICY "vinyl_tag_insert_auth" ON public."VINYL_TAG" FOR INSERT TO authenticated WITH CHECK (true);
-- Delete is deliberately disabled to prevent malicious removal of tags

-- USER_VINYL: public read / owner-only write
ALTER TABLE public."USER_VINYL" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "user_vinyl_read_all"     ON public."USER_VINYL";
DROP POLICY IF EXISTS "user_vinyl_insert_own"   ON public."USER_VINYL";
DROP POLICY IF EXISTS "user_vinyl_update_own"   ON public."USER_VINYL";
DROP POLICY IF EXISTS "user_vinyl_delete_own"   ON public."USER_VINYL";
CREATE POLICY "user_vinyl_read_all"   ON public."USER_VINYL" FOR SELECT USING (true);
CREATE POLICY "user_vinyl_insert_own" ON public."USER_VINYL" FOR INSERT TO authenticated
  WITH CHECK (auth.uid() = "USER_ID");
CREATE POLICY "user_vinyl_update_own" ON public."USER_VINYL" FOR UPDATE TO authenticated
  USING (auth.uid() = "USER_ID")
  WITH CHECK (auth.uid() = "USER_ID");
CREATE POLICY "user_vinyl_delete_own" ON public."USER_VINYL" FOR DELETE TO authenticated
  USING (auth.uid() = "USER_ID");

-- PROFILES: public read (nickname display) / owner-only write
ALTER TABLE public."PROFILES" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "profiles_read_all"   ON public."PROFILES";
DROP POLICY IF EXISTS "profiles_insert_own" ON public."PROFILES";
DROP POLICY IF EXISTS "profiles_update_own" ON public."PROFILES";
CREATE POLICY "profiles_read_all"   ON public."PROFILES" FOR SELECT USING (true);
CREATE POLICY "profiles_insert_own" ON public."PROFILES" FOR INSERT TO authenticated
  WITH CHECK (auth.uid() = "USER_ID");
CREATE POLICY "profiles_update_own" ON public."PROFILES" FOR UPDATE TO authenticated
  USING (auth.uid() = "USER_ID")
  WITH CHECK (auth.uid() = "USER_ID");

-- ============================================================
-- Admin & Support system (INQUIRY / INQUIRY_REPLY / EVENT_LOG)
-- Run this manually in the Supabase SQL Editor.
--
-- Access model:
--   * INQUIRY / INQUIRY_REPLY: owner-only read & insert. Admin access
--     goes through service-role API routes (bypasses RLS), so no
--     admin policies are needed here.
--   * EVENT_LOG: authenticated insert-only (own USER_ID). No SELECT
--     policy at all — only the service-role server can read it.
-- ============================================================

CREATE TABLE IF NOT EXISTS public."INQUIRY" (
    "INQUIRY_ID" bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "USER_ID"    uuid NOT NULL,
    "CATEGORY"   text NOT NULL DEFAULT 'GENERAL',  -- COMPLAINT | SUGGESTION | BUG | GENERAL
    "TITLE"      text NOT NULL,
    "CONTENT"    text NOT NULL,
    "STATUS"     text NOT NULL DEFAULT 'OPEN',     -- OPEN | ANSWERED | CLOSED
    "PLATFORM"   text NOT NULL DEFAULT 'WEB',      -- WEB | MOBILE
    "CREATED_AT" timestamp with time zone DEFAULT now(),
    "UPDATED_AT" timestamp with time zone DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public."INQUIRY_REPLY" (
    "REPLY_ID"   bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "INQUIRY_ID" bigint NOT NULL REFERENCES public."INQUIRY"("INQUIRY_ID") ON DELETE CASCADE,
    "USER_ID"    uuid,
    "IS_ADMIN"   boolean NOT NULL DEFAULT false,
    "CONTENT"    text NOT NULL,
    "CREATED_AT" timestamp with time zone DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public."EVENT_LOG" (
    "EVENT_ID"   bigint GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "EVENT_TYPE" text NOT NULL,                    -- LOGIN | SEARCH | SCAN | ALBUM_ADD | WISH_ADD | SHARE
    "USER_ID"    uuid,
    "PLATFORM"   text NOT NULL DEFAULT 'WEB',      -- WEB | MOBILE
    "META"       jsonb,
    "CREATED_AT" timestamp with time zone DEFAULT now()
);

CREATE INDEX IF NOT EXISTS "idx_event_log_type_created" ON public."EVENT_LOG" ("EVENT_TYPE", "CREATED_AT");
CREATE INDEX IF NOT EXISTS "idx_event_log_created"      ON public."EVENT_LOG" ("CREATED_AT");
CREATE INDEX IF NOT EXISTS "idx_inquiry_user_created"   ON public."INQUIRY" ("USER_ID", "CREATED_AT" DESC);
CREATE INDEX IF NOT EXISTS "idx_inquiry_reply_parent"   ON public."INQUIRY_REPLY" ("INQUIRY_ID");

-- INQUIRY: owner-only read / owner-only insert / no client update-delete
ALTER TABLE public."INQUIRY" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "inquiry_select_own" ON public."INQUIRY";
DROP POLICY IF EXISTS "inquiry_insert_own" ON public."INQUIRY";
CREATE POLICY "inquiry_select_own" ON public."INQUIRY" FOR SELECT TO authenticated
  USING ((select auth.uid()) = "USER_ID");
CREATE POLICY "inquiry_insert_own" ON public."INQUIRY" FOR INSERT TO authenticated
  WITH CHECK ((select auth.uid()) = "USER_ID" AND "STATUS" = 'OPEN');

-- INQUIRY_REPLY: readable by the inquiry owner; users can only add their
-- own non-admin replies (IS_ADMIN can't be forged from the client)
ALTER TABLE public."INQUIRY_REPLY" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "inquiry_reply_select_own" ON public."INQUIRY_REPLY";
DROP POLICY IF EXISTS "inquiry_reply_insert_own" ON public."INQUIRY_REPLY";
CREATE POLICY "inquiry_reply_select_own" ON public."INQUIRY_REPLY" FOR SELECT TO authenticated
  USING (EXISTS (SELECT 1 FROM public."INQUIRY" i
                 WHERE i."INQUIRY_ID" = "INQUIRY_REPLY"."INQUIRY_ID"
                   AND i."USER_ID" = (select auth.uid())));
CREATE POLICY "inquiry_reply_insert_own" ON public."INQUIRY_REPLY" FOR INSERT TO authenticated
  WITH CHECK ("IS_ADMIN" = false AND (select auth.uid()) = "USER_ID"
              AND EXISTS (SELECT 1 FROM public."INQUIRY" i
                          WHERE i."INQUIRY_ID" = "INQUIRY_REPLY"."INQUIRY_ID"
                            AND i."USER_ID" = (select auth.uid())));

-- EVENT_LOG: authenticated insert-only (own rows), intentionally NO select
-- policy — analytics reads happen exclusively through service-role routes
ALTER TABLE public."EVENT_LOG" ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "event_log_insert_own" ON public."EVENT_LOG";
CREATE POLICY "event_log_insert_own" ON public."EVENT_LOG" FOR INSERT TO authenticated
  WITH CHECK ((select auth.uid()) = "USER_ID");

-- Grant admin role (run ONCE for your own account, then sign out & back in;
-- app_metadata is only writable with the service role, so users can't
-- self-promote — do NOT put the role in user_metadata)
-- UPDATE auth.users
--   SET raw_app_meta_data = coalesce(raw_app_meta_data, '{}'::jsonb) || '{"role":"admin"}'
--   WHERE email = 'yjw127588@gmail.com';

-- ── Acquisition tracking: allow anonymous VISIT events ─────────
-- Landing/public-dashboard visits happen before login, so the anon role
-- may insert EVENT_LOG rows — but ONLY type VISIT with a null USER_ID
-- (prevents forging other users' activity). Run in the SQL Editor.
DROP POLICY IF EXISTS "event_log_insert_visit_anon" ON public."EVENT_LOG";
CREATE POLICY "event_log_insert_visit_anon" ON public."EVENT_LOG" FOR INSERT TO anon
  WITH CHECK ("EVENT_TYPE" = 'VISIT' AND "USER_ID" IS NULL);

-- ============================================================
-- Hardening migration (2026-07-11)
-- Run this whole section manually in the Supabase SQL Editor.
--
-- Fixes found in the security audit:
--   1. PROFILES had no DDL in this file (dashboard-only) → codified.
--   2. Nickname 30-day cooldown was client-side only → DB trigger.
--   3. Logged-in visits were dropped by RLS (insert_own requires
--      USER_ID = auth.uid(), but VISIT rows carry NULL) → new policy.
--   4. EVENT_LOG accepted any EVENT_TYPE / unbounded META from any
--      authenticated user → CHECK constraints + anon flood brake.
--   5. USER_VINYL allowed duplicate (user, album) rows, had no index
--      on USER_ID, no FK to auth.users, no STATUS/price validation.
--   6. INQUIRY enum values existed only as comments → CHECKs; user
--      replies now reopen the inquiry and bump UPDATED_AT.
--   7. avatars bucket policies lived only in the dashboard → codified
--      (uploads now go to a per-user folder: {uid}/avatar-*.ext).
-- ============================================================

-- 1. PROFILES table (previously created via dashboard only)
CREATE TABLE IF NOT EXISTS public."PROFILES" (
    "USER_ID" uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
    "DISPLAY_NAME" text UNIQUE,
    "LAST_NAME_CHANGED_AT" timestamp with time zone
);

-- 2. Nickname cooldown enforced in the DB. The trigger also owns
--    LAST_NAME_CHANGED_AT so clients can't backdate it via PostgREST.
CREATE OR REPLACE FUNCTION public.enforce_nickname_cooldown()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    NEW."LAST_NAME_CHANGED_AT" := now();
  ELSIF NEW."DISPLAY_NAME" IS DISTINCT FROM OLD."DISPLAY_NAME" THEN
    IF OLD."LAST_NAME_CHANGED_AT" IS NOT NULL
       AND OLD."LAST_NAME_CHANGED_AT" > now() - interval '30 days' THEN
      RAISE EXCEPTION '닉네임은 30일에 한 번만 변경 가능합니다.'
        USING ERRCODE = 'P0001';
    END IF;
    NEW."LAST_NAME_CHANGED_AT" := now();
  ELSE
    NEW."LAST_NAME_CHANGED_AT" := OLD."LAST_NAME_CHANGED_AT";
  END IF;
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS trg_nickname_cooldown ON public."PROFILES";
CREATE TRIGGER trg_nickname_cooldown
  BEFORE INSERT OR UPDATE ON public."PROFILES"
  FOR EACH ROW EXECUTE FUNCTION public.enforce_nickname_cooldown();

-- 3. Logged-in sessions also record VISIT rows with USER_ID NULL
--    (events.ts nulls it for VISIT), which event_log_insert_own rejected.
DROP POLICY IF EXISTS "event_log_insert_visit_auth" ON public."EVENT_LOG";
CREATE POLICY "event_log_insert_visit_auth" ON public."EVENT_LOG" FOR INSERT TO authenticated
  WITH CHECK ("EVENT_TYPE" = 'VISIT' AND "USER_ID" IS NULL);

-- 4a. EVENT_LOG value/size validation (NOT VALID: applies to new rows only,
--     so it can't fail on pre-existing data)
ALTER TABLE public."EVENT_LOG" DROP CONSTRAINT IF EXISTS "event_log_type_check";
ALTER TABLE public."EVENT_LOG" ADD CONSTRAINT "event_log_type_check"
  CHECK ("EVENT_TYPE" IN ('VISIT','SIGNUP','LOGIN','SEARCH','SCAN','ALBUM_ADD','WISH_ADD','SHARE')) NOT VALID;
ALTER TABLE public."EVENT_LOG" DROP CONSTRAINT IF EXISTS "event_log_meta_size_check";
ALTER TABLE public."EVENT_LOG" ADD CONSTRAINT "event_log_meta_size_check"
  CHECK ("META" IS NULL OR pg_column_size("META") < 4096) NOT VALID;

-- 4b. Flood brake: the anon key is public, so a curl loop could insert
--     unlimited VISIT rows (storage cost + poisoned acquisition metrics).
--     Hard-cap anonymous VISIT inserts at 120/min globally — legit traffic
--     never hits this, a spam loop stops doing damage after one minute.
--     (Uses idx_event_log_type_created, so the count is an index-only scan.)
CREATE OR REPLACE FUNCTION public.event_log_flood_brake()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF NEW."EVENT_TYPE" = 'VISIT' AND NEW."USER_ID" IS NULL THEN
    IF (SELECT count(*) FROM public."EVENT_LOG"
        WHERE "EVENT_TYPE" = 'VISIT'
          AND "CREATED_AT" > now() - interval '1 minute') >= 120 THEN
      RAISE EXCEPTION 'VISIT rate limit exceeded' USING ERRCODE = 'P0002';
    END IF;
  END IF;
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS trg_event_log_flood_brake ON public."EVENT_LOG";
CREATE TRIGGER trg_event_log_flood_brake
  BEFORE INSERT ON public."EVENT_LOG"
  FOR EACH ROW EXECUTE FUNCTION public.event_log_flood_brake();

-- 5. USER_VINYL integrity: dedupe, then one row per (user, album),
--    index for the hot USER_ID lookups, FK cleanup on account deletion,
--    and STATUS/price validation.
DELETE FROM public."USER_VINYL" a
  USING public."USER_VINYL" b
  WHERE a."USER_VINYL_ID" > b."USER_VINYL_ID"
    AND a."USER_ID" = b."USER_ID"
    AND a."ALBUM_ID" = b."ALBUM_ID";
ALTER TABLE public."USER_VINYL" DROP CONSTRAINT IF EXISTS "user_vinyl_user_album_key";
ALTER TABLE public."USER_VINYL" ADD CONSTRAINT "user_vinyl_user_album_key"
  UNIQUE ("USER_ID", "ALBUM_ID");
CREATE INDEX IF NOT EXISTS "idx_user_vinyl_user" ON public."USER_VINYL" ("USER_ID");
DELETE FROM public."USER_VINYL" uv
  WHERE NOT EXISTS (SELECT 1 FROM auth.users u WHERE u.id = uv."USER_ID");
ALTER TABLE public."USER_VINYL" DROP CONSTRAINT IF EXISTS "user_vinyl_user_fk";
ALTER TABLE public."USER_VINYL" ADD CONSTRAINT "user_vinyl_user_fk"
  FOREIGN KEY ("USER_ID") REFERENCES auth.users(id) ON DELETE CASCADE;
ALTER TABLE public."USER_VINYL" DROP CONSTRAINT IF EXISTS "user_vinyl_status_check";
ALTER TABLE public."USER_VINYL" ADD CONSTRAINT "user_vinyl_status_check"
  CHECK ("STATUS" IN ('OWNED','WISH')) NOT VALID;
ALTER TABLE public."USER_VINYL" DROP CONSTRAINT IF EXISTS "user_vinyl_price_check";
ALTER TABLE public."USER_VINYL" ADD CONSTRAINT "user_vinyl_price_check"
  CHECK ("PURCHASE_PRICE" IS NULL OR ("PURCHASE_PRICE" >= 0 AND "PURCHASE_PRICE" <= 100000000)) NOT VALID;

-- 6a. INQUIRY enum comments promoted to real constraints
ALTER TABLE public."INQUIRY" DROP CONSTRAINT IF EXISTS "inquiry_category_check";
ALTER TABLE public."INQUIRY" ADD CONSTRAINT "inquiry_category_check"
  CHECK ("CATEGORY" IN ('COMPLAINT','SUGGESTION','BUG','GENERAL')) NOT VALID;
ALTER TABLE public."INQUIRY" DROP CONSTRAINT IF EXISTS "inquiry_status_check";
ALTER TABLE public."INQUIRY" ADD CONSTRAINT "inquiry_status_check"
  CHECK ("STATUS" IN ('OPEN','ANSWERED','CLOSED')) NOT VALID;
ALTER TABLE public."INQUIRY" DROP CONSTRAINT IF EXISTS "inquiry_platform_check";
ALTER TABLE public."INQUIRY" ADD CONSTRAINT "inquiry_platform_check"
  CHECK ("PLATFORM" IN ('WEB','MOBILE')) NOT VALID;

-- 6b. A user reply must reopen the inquiry and bump UPDATED_AT so the
--     admin sees the follow-up. Clients have no UPDATE policy on INQUIRY
--     (by design), so this runs as a SECURITY DEFINER trigger instead.
CREATE OR REPLACE FUNCTION public.on_inquiry_reply()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  UPDATE public."INQUIRY"
     SET "UPDATED_AT" = now(),
         "STATUS" = CASE WHEN NEW."IS_ADMIN" THEN "STATUS" ELSE 'OPEN' END
   WHERE "INQUIRY_ID" = NEW."INQUIRY_ID";
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS trg_on_inquiry_reply ON public."INQUIRY_REPLY";
CREATE TRIGGER trg_on_inquiry_reply
  AFTER INSERT ON public."INQUIRY_REPLY"
  FOR EACH ROW EXECUTE FUNCTION public.on_inquiry_reply();

-- 7. avatars bucket: codified policies. App code now uploads to a
--    per-user folder ({uid}/avatar-{ts}.ext) so ownership is checkable.
--    Public read is intended (avatars render on public dashboards).
DROP POLICY IF EXISTS "avatar_read_all" ON storage.objects;
CREATE POLICY "avatar_read_all" ON storage.objects FOR SELECT
  USING (bucket_id = 'avatars');
DROP POLICY IF EXISTS "avatar_upload_own" ON storage.objects;
CREATE POLICY "avatar_upload_own" ON storage.objects FOR INSERT TO authenticated
  WITH CHECK (bucket_id = 'avatars' AND (storage.foldername(name))[1] = auth.uid()::text);
DROP POLICY IF EXISTS "avatar_delete_own" ON storage.objects;
CREATE POLICY "avatar_delete_own" ON storage.objects FOR DELETE TO authenticated
  USING (bucket_id = 'avatars' AND (storage.foldername(name))[1] = auth.uid()::text);

-- ============================================================
-- Founding member badge migration (2026-07-12)
-- Run this whole section manually in the Supabase SQL Editor.
--
-- Adds a permanent, DB-assigned signup number to PROFILES so a "first
-- 100 users" badge can't be spoofed. Every other badge is evaluated
-- client-side from the user's own collection stats and self-reported
-- via updateUnlockedBadges() with no server validation — fine for
-- vanity badges, not fine for something meant to be scarce/exclusive.
-- ============================================================

-- 1. One monotonically increasing number per profile, assigned once.
CREATE SEQUENCE IF NOT EXISTS public.profiles_signup_seq;
ALTER TABLE public."PROFILES" ADD COLUMN IF NOT EXISTS "SIGNUP_NUMBER" integer;

-- 2. Trigger owns SIGNUP_NUMBER (same pattern as enforce_nickname_cooldown
--    owning LAST_NAME_CHANGED_AT) — a client can UPDATE its own PROFILES
--    row under RLS, but can never move up the queue this way.
CREATE OR REPLACE FUNCTION public.assign_signup_number()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    NEW."SIGNUP_NUMBER" := nextval('public.profiles_signup_seq');
  ELSIF OLD."SIGNUP_NUMBER" IS NOT NULL THEN
    -- Already assigned — immutable, ignore whatever the client sent.
    NEW."SIGNUP_NUMBER" := OLD."SIGNUP_NUMBER";
  END IF;
  -- else: OLD.SIGNUP_NUMBER IS NULL (not yet backfilled) — let NEW's
  -- value through. Only matters for step 3's one-time backfill UPDATE
  -- below; every row inserted after this migration gets its number at
  -- INSERT time, so OLD.SIGNUP_NUMBER is never NULL for it again.
  RETURN NEW;
END;
$$;
DROP TRIGGER IF EXISTS trg_assign_signup_number ON public."PROFILES";
CREATE TRIGGER trg_assign_signup_number
  BEFORE INSERT OR UPDATE ON public."PROFILES"
  FOR EACH ROW EXECUTE FUNCTION public.assign_signup_number();

-- 3. Some accounts (e.g. anyone whose displayName was already set before
--    this migration ever existed) never went through updateProfile()'s
--    "only upsert PROFILES when the name is changing" path, so they have
--    no PROFILES row at all and would be silently excluded from both the
--    badge and the backfill below. Create the missing rows from their
--    existing auth metadata. Trigger is off here since its INSERT branch
--    would otherwise force a fresh nextval() instead of leaving room for
--    step 4's full, order-correct renumber.
ALTER TABLE public."PROFILES" DISABLE TRIGGER trg_assign_signup_number;
INSERT INTO public."PROFILES" ("USER_ID", "DISPLAY_NAME")
SELECT u.id, u.raw_user_meta_data->>'displayName'
FROM auth.users u
LEFT JOIN public."PROFILES" p ON p."USER_ID" = u.id
WHERE p."USER_ID" IS NULL AND u.raw_user_meta_data->>'displayName' IS NOT NULL
ON CONFLICT ("USER_ID") DO NOTHING;

-- 4. Full (re-)number of every profile by real auth.users.created_at
--    (PROFILES has no CREATED_AT of its own, and LAST_NAME_CHANGED_AT
--    drifts forward if they ever changed their nickname). Safe to re-run.
WITH ordered AS (
  SELECT p."USER_ID", row_number() OVER (ORDER BY u.created_at) AS rn
  FROM public."PROFILES" p
  JOIN auth.users u ON u.id = p."USER_ID"
)
UPDATE public."PROFILES" p
SET "SIGNUP_NUMBER" = ordered.rn
FROM ordered
WHERE p."USER_ID" = ordered."USER_ID";
ALTER TABLE public."PROFILES" ENABLE TRIGGER trg_assign_signup_number;

-- 5. Point the sequence past the (re-)numbered rows so new signups
--    continue the count instead of colliding with it.
SELECT setval('public.profiles_signup_seq', GREATEST((SELECT count(*) FROM public."PROFILES"), 1));
